    if (contentType.includes("xml") || contentType.includes("rss") || contentType.includes("atom")) {
      const hostname = parsed.hostname.replace("www.", "");
      return [{
        id: `detected-${slugify(hostname)}`,
        name: hostname,
        url,
        category: "Detectado",
        source: "auto-detect"
      }];
    }
